// Combine all knowledge base rows into a single readable text block
const kbRows = $input.all();
const config = $('2. Set — Config Values').item.json;
const userMessage = $('1. Chat Message Received').item.json.chatInput || '';

if (!kbRows || kbRows.length === 0) {
  return [{
    json: {
      knowledgeBase: 'Knowledge base is empty. Please add Q&A rows to the SEO FAQ sheet.',
      userMessage,
      sessionId: config.sessionId,
      botPersona: config.botPersona,
      companyName: config.companyName,
      logSheetId: config.logSheetId,
      logSheetName: config.logSheetName,
      timestamp: new Date().toISOString().replace('T', ' ').substring(0, 16)
    }
  }];
}

// Build knowledge base text from all rows
let kbText = '';
kbRows.forEach((row, index) => {
  const q = row.json['Question'] || row.json['question'] || '';
  const a = row.json['Answer'] || row.json['answer'] || '';
  const cat = row.json['Category'] || row.json['category'] || 'General';
  if (q && a) {
    kbText += `Q${index + 1} [${cat}]: ${q}\nA${index + 1}: ${a}\n\n`;
  }
});

return [{
  json: {
    knowledgeBase: kbText || 'No valid Q&A pairs found in knowledge base.',
    userMessage,
    sessionId: config.sessionId,
    botPersona: config.botPersona,
    companyName: config.companyName,
    logSheetId: config.logSheetId,
    logSheetName: config.logSheetName,
    timestamp: new Date().toISOString().replace('T', ' ').substring(0, 16)
  }
}];
